package com.example.login;

import android.content.Context;
import android.content.SharedPreferences;

import androidx.annotation.Nullable;

public final class AuthPrefs {
    private static final String PREFS = "auth_prefs";
    private static final String KEY_EMAIL = "email";
    private static final String KEY_TOKEN = "token";

    private AuthPrefs() {}

    private static SharedPreferences sp(Context context) {
        return context.getApplicationContext().getSharedPreferences(PREFS, Context.MODE_PRIVATE);
    }

    public static void save(Context context, String email, String token) {
        sp(context).edit()
                .putString(KEY_EMAIL, email)
                .putString(KEY_TOKEN, token)
                .apply();
    }

    public static boolean isLoggedIn(Context context) {
        String token = getToken(context);
        return token != null && !token.trim().isEmpty();
    }

    @Nullable
    public static String getEmail(Context context) {
        return sp(context).getString(KEY_EMAIL, null);
    }

    @Nullable
    public static String getToken(Context context) {
        return sp(context).getString(KEY_TOKEN, null);
    }

    public static void clear(Context context) {
        sp(context).edit().clear().apply();
    }
}

